"use strict";(globalThis.webpackChunkhello_site=globalThis.webpackChunkhello_site||[]).push([[5609],{6099:e=>{e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"/2026/05/19/","metadata":{"permalink":"/til/2026/05/19/","source":"@site/til/2026-05-19.md","title":"2026-05-19","description":"Circuit Breaker \uc758 \uc804\ud30c","date":"2026-05-19T00:00:00.000Z","tags":[{"inline":true,"label":"resilience","permalink":"/til/tags/resilience"}],"hasTruncateMarker":false,"authors":[{"name":"June","title":"Backend Developer","socials":{"github":"https://github.com/June0619"},"imageURL":"https://avatars.githubusercontent.com/u/54339266?v=4","key":"June","page":null}],"frontMatter":{"title":"2026-05-19","date":"2026-05-19T00:00:00.000Z","authors":["June"],"tags":["resilience"]},"unlisted":false,"nextItem":{"title":"2026-05-13","permalink":"/til/2026/05/13/"}},"content":"## Circuit Breaker \uc758 \uc804\ud30c\\nCircuit Breaker \uc758 \uacbd\uc6b0 MSA \ud658\uacbd\uc5d0\uc11c \ud2b9\uc815 \uc11c\ube44\uc2a4\ub9cc \uc11c\ud0b7\ube0c\ub808\uc774\ucee4\uac00 \ub3d9\uc791\ud560 \uc218 \uc788\ub2e4. \uc774 \uacbd\uc6b0 \uc0ac\uc6a9\uc790 \uacbd\ud5d8\uce21\uba74\uc5d0\uc11c \ud2b9\uc815 \uc720\uc800\ub9cc \uc7a5\uc560\ub97c \uacbd\ud5d8\ud558\ub294 \ub4f1 \uc2e0\ub8b0\ub3c4 \ud558\ub77d\uc73c\ub85c \uc774\uc5b4\uc9c4\ub2e4. \ub530\ub77c\uc11c Redis, Kafka, Service Mesh \ub4f1 \uac00\uc6a9\ud55c \uc778\ud504\ub77c\ub97c \ud65c\uc6a9\ud558\uc5ec \ud574\ub2f9 \uc0c1\ud669\uc744 \ucc28\ub2e8\ud558\ub294\uac8c \uc88b\ub2e4.\\n\\n## Fallback\\n- \uc7a5\uc560 \uc0c1\ud669 \ubc1c\uc0dd \uc2dc \ud6c4\uc18d\ucc98\ub9ac \ubc29\ud5a5\\n    1. \ub2e8\uc21c \uc2e4\ud328 \ubc18\ud658: \uc57d\uc18d\ub41c \uc2e4\ud328 \ud398\uc774\ub85c\ub4dc \ubc18\ud658\\n    2. \uc7ac\uc2dc\ub3c4 \ud050\uc5d0 \uc800\uc7a5: \uc11c\ube44\uc2a4 \uc7a5\uc560\uac00 \uc77c\uc2dc\uc801\uc778 \uacbd\uc6b0 \uc7ac\uc2dc\ub3c4\ub97c \ud1b5\ud574 \ubcf5\uad6c\\n    3. \ub300\uccb4 \ub3d9\uc791 \uc218\ud589: Kakao \ub300\uc2e0 SMS \ubc1c\uc1a1 \ub4f1\\n    4. \uc608\uc678 \ubcc0\ud658: \ud55c\ubc88 \ucd94\uc0c1\ud654 \ub41c \uc608\uc678\ub85c \uac10\uc2f8 \uc804\ud30c (\uc608: `NetworkException` -> `PaymentFailedException`)\\n\\n## Graceful Degradation\\n- \uc2dc\uc2a4\ud15c \uc77c\ubd80 \uae30\ub2a5\uc774 \uc7a5\uc560\ub85c \uc778\ud574 \uc911\ub2e8 \ub418\ub354\ub77c\ub3c4 \ub098\uba38\uc9c0 \uae30\ub2a5\uc740 \ub3d9\uc791\ud558\ub3c4\ub85d \ubcf4\ud638\ud558\ub294 \uac83\\n    - \ub2e8\uc21c \ud68c\ub85c\ucc28\ub2e8\uc774\ub098 \uc7a5\uc560\ubcf5\uad6c \ub85c\uc9c1 \uc678\uc5d0 \uba54\ud2b8\ub9ad \uc218\uc9d1 \ub4f1 \ubcf5\uc7a1\ud55c \ub3d9\uc791\uc774 \uc694\uad6c\ub41c\ub2e4."},{"id":"/2026/05/13/","metadata":{"permalink":"/til/2026/05/13/","source":"@site/til/2026-05-13.md","title":"2026-05-13","description":"Circuit Breaker","date":"2026-05-13T00:00:00.000Z","tags":[{"inline":true,"label":"resilience","permalink":"/til/tags/resilience"},{"inline":true,"label":"spring","permalink":"/til/tags/spring"}],"hasTruncateMarker":false,"authors":[{"name":"June","title":"Backend Developer","socials":{"github":"https://github.com/June0619"},"imageURL":"https://avatars.githubusercontent.com/u/54339266?v=4","key":"June","page":null}],"frontMatter":{"title":"2026-05-13","date":"2026-05-13T00:00:00.000Z","authors":["June"],"tags":["resilience","spring"]},"unlisted":false,"prevItem":{"title":"2026-05-19","permalink":"/til/2026/05/19/"},"nextItem":{"title":"2026-05-12","permalink":"/til/2026/05/12/"}},"content":"## Circuit Breaker\\n\\n### \uac1c\uc694\\n- \ud2b9\uc815 \uc11c\ubc84\uc5d0 \uc2e4\ud589\ud558\ub294 \uc694\uccad\uc758 \uc2e4\ud328 \ube48\ub3c4\uac00 \ub108\ubb34 \ub192\uc544\uc9c4\ub2e4\uba74 \uc7a0\uc2dc \uc694\uccad\uc744 \ucc28\ub2e8\ud55c\ub2e4.\\n- \uc774\ub97c \ud1b5\ud574 \uc11c\ubc84\uc758 \ubd80\ud558\ub97c \uc904\uc774\uace0 \ud68c\ubcf5\ud560 \uc2dc\uac04\uc744 \uc900\ub2e4.  \\n- \uc8fc\ub85c \uc2a4\ud30c\uc774\ud06c \ud2b8\ub798\ud53d \ub4f1 \uc21c\uac04\uc801\uc73c\ub85c \ud3ed\uc99d\ud558\ub294 \ud2b8\ub798\ud53d \ub300\uc751\uc5d0 \uc720\ud6a8\ud558\ub2e4.\\n\\n### \uc8fc\uc758\uc810\\n- \ud074\ub77c\uc774\uc5b8\ud2b8 \uc785\uc7a5\uc5d0\uc11c \uc11c\ud0b7\ube0c\ub808\uc774\ucee4\uc758 fallback \ub3d9\uc791\uc73c\ub85c \uc7ac\uc694\uccad\uc744 \ubcf4\ub0b4\ub294 \uacbd\uc6b0 \uc11c\ubc84\uc5d0\uc11c\ub294 \uc774\ubbf8 \ud050\uc5d0 \ub123\uace0 \uc2e4\ud589\uc911\uc778 \ub3d9\uc791\uc77c \uc218 \uc788\ub2e4. \\n- \uc774\ub7f0 \uacbd\uc6b0 \uc911\ubcf5\uc2e4\ud589\uc758 \uc704\ud5d8\uc774 \uc788\uc73c\uba70 \uc11c\ud0b7\ube0c\ub808\uc774\ucee4 \ub3d9\uc791 \ub300\uc0c1\uc774 \ub418\ub294 API\ub294 \uba71\ub4f1\ud558\uac8c \uc124\uacc4\ud558\ub294 \uac83\uc774 \uc911\uc694\ud558\ub2e4.\\n- \uc544\ub798 \uc608\uc81c\ucf54\ub4dc\uc640 \uac19\uc774 `\uc11c\ud0b7\ube0c\ub808\uc774\ucee4 \ub3d9\uc791 \ub300\uc0c1` \uacfc \uadf8\ub807\uc9c0 \uc54a\uc740 \uc608\uc678\ub97c \uc798 \uad6c\ubd84\ud55c\ub2e4.\\n\\n```java\\n@Override\\n@CircuitBreaker(name = MAIL_SERVICE_CB, fallbackMethod = \\"sendMailFallback\\")\\npublic String sendMail(String email) {\\n    log.debug(\\"[Circuit Breaker: {}] Attempting to send mail for email: {}\\", MAIL_SERVICE_CB, email);\\n    EmailRequest request = new EmailRequest(email);\\n\\n    // WebClient \ud638\ucd9c \ubc0f \uacb0\uacfc \ucc98\ub9ac\\n    // .block()\uc744 \uc0ac\uc6a9\ud558\ubbc0\ub85c, \uc804\uccb4 \uba54\uc11c\ub4dc\ub294 \ub3d9\uae30\uc801\uc73c\ub85c \ub3d9\uc791\ud569\ub2c8\ub2e4.\\n    // \uc644\uc804\ud55c \ube44\ub3d9\uae30 \ucc98\ub9ac\ub97c \uc6d0\ud55c\ub2e4\uba74 Mono<String>\uc744 \ubc18\ud658\ud558\ub3c4\ub85d \uc218\uc815\ud574\uc57c \ud569\ub2c8\ub2e4.\\n    return webClient.post()\\n            .uri(MAIL_SEND_URI) // \uc0c1\uc218 \uc0ac\uc6a9\\n            .bodyValue(request)\\n            .retrieve()\\n            // --- 5xx \uc11c\ubc84 \uc5d0\ub7ec \ucc98\ub9ac ---\\n            // onStatus\ub97c \uc0ac\uc6a9\ud558\uc5ec \ud2b9\uc815 \uc0c1\ud0dc \ucf54\ub4dc\uc5d0 \ub300\ud55c \ucc98\ub9ac\ub97c \uba85\ud655\ud788 \ud568\\n            .onStatus(status -> status.is5xxServerError(), clientResponse ->\\n                    clientResponse.bodyToMono(String.class)\\n                            .flatMap(errorBody -> {\\n                                // 5xx \uc5d0\ub7ec\ub294 \ubcc4\ub3c4\uc758 \uc608\uc678(MailSendException)\ub85c \ucc98\ub9ac (\uc11c\ud0b7 \uae30\ub85d \uc548 \ub428 \uba85\uc2dc)\\n                                // \uc7a5\uc560 \uc751\ub2f5\uc744 \uc11c\ubc84\uac00 \uc81c\ub54c \uc900 \uac83 \uc774\ubbc0\ub85c \uc11c\ud0b7\ube0c\ub808\uc774\ucee4 \ub3d9\uc791 \ub300\uc0c1\uc774 \uc544\ub2d8\\n                                log.warn(\\"[CB: {}] Mail service returned 5xx server error for {}: {}\\", MAIL_SERVICE_CB, email, errorBody);\\n                                return Mono.error(new MailSendException(\\"Mail service server error: \\" + errorBody));\\n                            })\\n            )\\n            .bodyToMono(String.class) // \uc131\uacf5 \uc2dc \uc751\ub2f5 \ubcf8\ubb38 \ucc98\ub9ac\\n            // --- \ud0c0\uc784\uc544\uc6c3 \ucc98\ub9ac ---\\n            // timeout \uc5f0\uc0b0\uc790\ub97c \uc0ac\uc6a9\ud558\uc5ec \uc9c0\uc815\ub41c \uc2dc\uac04 \ub0b4 \uc751\ub2f5 \uc5c6\uc744 \uc2dc \uc608\uc678 \ubc1c\uc0dd\\n            // MailServiceTimeoutException\uc740 RecordException\uc744 \uc0c1\uc18d\ud55c\ub2e4\uace0 \uac00\uc815 (\uc2e4\ud328 \uae30\ub85d\ub428)\\n            .timeout(DEFAULT_TIMEOUT, Mono.error(\\n                    () -> new MailServiceTimeoutException(\\"Timeout after \\" + DEFAULT_TIMEOUT + \\" for \\" + email)) // \uc9c0\uc5f0 \uc0dd\uc131\\n            )\\n            // --- \uc131\uacf5 \ub85c\uadf8 ---\\n            .doOnSuccess(response -> log.debug(\\"[CB: {}] Successfully sent mail for {}\\", MAIL_SERVICE_CB, email))\\n            // --- \uc5d0\ub7ec \ub9e4\ud551 \ubc0f \ucc98\ub9ac ---\\n            // onErrorMap\uc744 \uc0ac\uc6a9\ud558\uc5ec \ud2b9\uc815 \uc5d0\ub7ec\ub97c \uc11c\ud0b7 \ube0c\ub808\uc774\ucee4\uac00 \uae30\ub85d\ud560 \uc608\uc678\ub85c \ubcc0\ud658\\n            .onErrorMap(this::mapToCircuitBreakerException) // \uc5d0\ub7ec \ub9e4\ud551 \uba54\uc11c\ub4dc \ucc38\uc870\\n            // --- \ube14\ub85c\ud0b9 \ud638\ucd9c ---\\n            // \ub9ac\uc561\ud2f0\ube0c \uc2a4\ud2b8\ub9bc \uacb0\uacfc\ub97c \ub3d9\uae30\uc801\uc73c\ub85c \uae30\ub2e4\ub9bc\\n            .block();\\n}\\n```\\n\\n```java\\npublic class MailServiceTimeoutException extends RecordException {\\n\\n    public MailServiceTimeoutException(String message) {\\n        super(message);\\n    }\\n\\n    public MailServiceTimeoutException(String message, Throwable cause) {\\n        super(message, cause);\\n    }\\n\\n}\\n```"},{"id":"/2026/05/12/","metadata":{"permalink":"/til/2026/05/12/","source":"@site/til/2026-05-12.md","title":"2026-05-12","description":"Timeout\uacfc \uc7a5\uc560\uc804\ud30c \ubc29\uc9c0","date":"2026-05-12T00:00:00.000Z","tags":[{"inline":true,"label":"resilience","permalink":"/til/tags/resilience"},{"inline":true,"label":"spring","permalink":"/til/tags/spring"}],"hasTruncateMarker":false,"authors":[{"name":"June","title":"Backend Developer","socials":{"github":"https://github.com/June0619"},"imageURL":"https://avatars.githubusercontent.com/u/54339266?v=4","key":"June","page":null}],"frontMatter":{"title":"2026-05-12","date":"2026-05-12T00:00:00.000Z","authors":["June"],"tags":["resilience","spring"]},"unlisted":false,"prevItem":{"title":"2026-05-13","permalink":"/til/2026/05/13/"}},"content":"## Timeout\uacfc \uc7a5\uc560\uc804\ud30c \ubc29\uc9c0\\n\\n> \uc801\uc808\ud55c \ud0c0\uc784\uc544\uc6c3 \uc124\uc815\uc740 \uc608\uce21\ud558\uc9c0 \ubabb\ud55c \uc678\ubd80 \uc11c\ube44\uc2a4\ub098 \ub124\ud2b8\uc6cc\ud06c \uc7a5\uc560\uc5d0 \uc790\uc6d0\uc744 \uc624\ub798 \uc810\uc720\ub2f9\ud558\uc9c0 \uc54a\ub3c4\ub85d \ud574\uc900\ub2e4.\\n\\n```java\\n    public void callExternalApi(ExternalRequest reuqest) {\\n        webClient.post()\\n            .uri(\\"/api\\")\\n            .contentType(MediaType.APPLICATION_JSON)\\n            .bodyValue(request)\\n            .retrieve()\\n            //\uba85\uc2dc\uc801\uc73c\ub85c 5xx Status \uc608\uc678\ub3c4 \ubcc0\ud658\\n            .onStatus(status -> status.is5xxServerError(), clientResponse ->\\n                    clientResponse.bodyToMono(String.class)\\n                        .flatMap(errorBody ->\\n                            Mono.<Throwable>error(new ExternalServerErrorException(\\"\uc678\ubd80 \uc11c\ube44\uc2a4 500\uc5d0\ub7ec \ubc1c\uc0dd\\"))\\n                        )\\n            )\\n            .bodyToMono(ExternalResponse.class)\\n            .onErrorMap(throwable -> {\\n                    if (throwable instanceof ReadTimeoutException ||\\n                            (throwable.getCause() != null && throwable.getCause() instanceof ReadTimeoutException)) {\\n                        return new ExternalServiceTimeoutException(\\"\uc678\ubd80 \uc11c\ube44\uc2a4 \ud0c0\uc784\uc544\uc6c3 \ubc1c\uc0dd\\", throwable);\\n                    }\\n                    return throwable;\\n                })\\n    }\\n\\n```\\n\\n- 5xx Status \uc758 \uacbd\uc6b0\uc5d0\ub3c4 \ub3c4\uba54\uc778 \uc608\uc678\uc5d0 \ub9de\uac8c \ubcc0\ud658\ud558\uc5ec \ub2e4\ub8e8\uc5b4\uc57c \ud55c\ub2e4.\\n- Timeout \uc7a5\uc560 \uc5ed\uc2dc\ub3c4 \ub3c4\uba54\uc778 \uc608\uc678\uc5d0 \ub9de\uac8c \ub2e4\ub8ec\ub2e4.\\n    - \ud2b9\ud788 Retryable \ud55c \uacbd\uc6b0\uac00 \ub9ce\uc73c\ubbc0\ub85c \ubd80\ubaa8 \uc608\uc678\ub97c \uc798 \uc124\uc815\ud558\uc5ec \ubcf5\uad6c \uac00\ub2a5\ud55c \uc2dc\uc2a4\ud15c\uc744 \ub9cc\ub4e0\ub2e4."}]}}')}}]);